def extract_js_urls(html: str) -> list[str]:
    urls = re.findall(r'src="([^"]+\.js)"', html)
    normalized = []
    for url in urls:
        if url.startswith("//"):
            normalized.append(f"https:{url}")
        else:
            normalized.append(url)
    return normalized


def fetch_bundle_text(session: requests.Session, page_url: str) -> tuple[dict[str, Any], str]:
    resp = session.get(page_url, timeout=20)
    info = {
        "page_url": page_url,
        "status_code": resp.status_code,
        "content_type": resp.headers.get("content-type", ""),
        "html_prefix": resp.text[:500],
    }
    html = resp.text
    js_urls = extract_js_urls(html)
    info["js_urls"] = js_urls
    bundle_url = next((u for u in js_urls if "/static/js/index." in u), "")
    info["bundle_url"] = bundle_url
    bundle_text = ""
    if bundle_url:
        bundle_resp = session.get(bundle_url, timeout=30)
        info["bundle_status_code"] = bundle_resp.status_code
        info["bundle_content_type"] = bundle_resp.headers.get("content-type", "")
        bundle_text = bundle_resp.text if bundle_resp.ok else ""
    return info, bundle_text


def detect_api_patterns(bundle_text: str) -> dict[str, Any]:
    api_routes = sorted(set(re.findall(r"/caishen_fund/[A-Za-z0-9_./-]+", bundle_text)))
    hints = {route: (route in bundle_text) for route in KNOWN_ENDPOINT_HINTS}
    param_hints: dict[str, dict[str, Any]] = {}

    stock_idx = bundle_text.find('key:"requestStockPosition"')
    if stock_idx != -1:
        snippet = bundle_text[max(0, stock_idx - 200) : stock_idx + 1500]
        param_hints["stock_position"] = {
            "method_name": "requestStockPosition",
            "endpoint": "/caishen_fund/pc/asset/v1/stock_position",
            "params_detected": sorted(set(re.findall(r"manual_id|fund_key|rzrq_fund_key|userid", snippet))),
            "snippet": snippet[:1200],
        }

    hist_idx = bundle_text.find('key:"queryAccountHistory"')
    if hist_idx != -1:
        snippet = bundle_text[max(0, hist_idx - 200) : hist_idx + 1600]
        param_hints["account_history"] = {
            "method_name": "queryAccountHistory",
            "endpoint": "/caishen_fund/pc/account/v2/get_money_history",
            "params_detected": sorted(
                set(
                    re.findall(
                        r"manual_id|fund_key|rzrq_fund_key|fundid|custid|user_id|start_date|end_date|query_list|page|count|sort_type|sort_order|h5id",
                        snippet,
                    )
                )
            ),
            "snippet": snippet[:1200],
        }

    return {
        "api_routes": api_routes,
        "known_endpoint_hits": hints,
        "param_hints": param_hints,
    }


def sqlite_rows(db_path: Path, query: str, params: tuple[Any, ...] = ()) -> list[tuple[Any, ...]]:
    tmp = Path(tempfile.mkstemp(suffix=".sqlite")[1])
    try:
        shutil.copy2(db_path, tmp)
        con = sqlite3.connect(tmp)
        try:
            cur = con.cursor()
            return cur.execute(query, params).fetchall()
        finally:
            con.close()
    finally:
        try:
            tmp.unlink()
        except Exception:
            pass


def inspect_history(history_db: Path) -> list[dict[str, Any]]:
    if not history_db.exists():
        return []
    rows = sqlite_rows(
        history_db,
        "select url, title, visit_count, last_visit_time from urls where url like '%tzzb.10jqka.com.cn%' order by last_visit_time desc limit 20",
    )
    results = []
    for url, title, visit_count, last_visit_time in rows:
        redacted_url = re.sub(r"(/myAccount/a/)([^/?#]+)", lambda m: m.group(1) + redact_text(m.group(2)), str(url))
        results.append(
            {
                "url": redacted_url,
                "title": title,
                "visit_count": visit_count,
                "last_visit_time": chromium_ts_to_iso(last_visit_time),
            }
        )
    return results


