def load_request_spec(path: Path) -> dict[str, Any]:
    payload = json.loads(path.read_text(encoding="utf-8"))
    if not isinstance(payload, dict):
        raise ValueError("request json 顶层必须是对象")
    return payload


def build_cookie_header(cookies: Any) -> str:
    if isinstance(cookies, str):
        return cookies.strip()
    if isinstance(cookies, dict):
        items = []
        for k, v in cookies.items():
            items.append(f"{k}={v}")
        return "; ".join(items)
    return ""


def replay_request(spec: dict[str, Any]) -> requests.Response:
    url = str(spec.get("url") or "").strip()
    if not url:
        raise ValueError("request json 缺少 url")
    method = str(spec.get("method") or "GET").upper()
    headers = {str(k): str(v) for k, v in (spec.get("headers") or {}).items()}
    if "User-Agent" not in headers and "user-agent" not in headers:
        headers["User-Agent"] = DEFAULT_USER_AGENT
    cookie_header = build_cookie_header(spec.get("cookies"))
    if cookie_header and not any(k.lower() == "cookie" for k in headers):
        headers["Cookie"] = cookie_header
    timeout = int(spec.get("timeout") or 20)

    session = request_session()
    req_kwargs: dict[str, Any] = {"headers": headers, "timeout": timeout}
    if "params" in spec:
        req_kwargs["params"] = spec["params"]
    if "json" in spec:
        req_kwargs["json"] = spec["json"]
    if "data" in spec:
        req_kwargs["data"] = spec["data"]

    response = session.request(method, url, **req_kwargs)
    return response


def parse_stock_position_payload(payload: Any, request_url: str, request_spec: dict[str, Any]) -> list[Holding]:
    if not isinstance(payload, dict):
        return []
    position = payload.get("position")
    if not isinstance(position, list):
        ex_data = payload.get("ex_data")
        if isinstance(ex_data, dict) and isinstance(ex_data.get("position"), list):
            position = ex_data.get("position")
        else:
            return []
    spec_data = request_spec.get("data") or request_spec.get("json") or {}
    ledger_ids = [str(spec_data.get(k) or "").strip() for k in ["manual_id", "fund_key", "rzrq_fund_key"] if str(spec_data.get(k) or "").strip()]
    holdings: list[Holding] = []
    for item in position:
        if not isinstance(item, dict):
            continue
        symbol = normalize_code(item.get("code") or item.get("stock_code"), item.get("market") or item.get("market_code"))
        if not symbol:
            continue
        qty_raw = item.get("count") or item.get("entry_count") or item.get("qty") or 0
        try:
            quantity = int(float(qty_raw))
        except Exception:
            quantity = 0
        if quantity <= 0:
            continue
        cost_price = None
        for key in ["cost", "entry_price", "cbjg"]:
            if key in item and str(item.get(key) or "").strip():
                value = str(item.get(key)).replace("HK$", "").replace(",", "")
                try:
                    cost_price = float(value)
                except Exception:
                    cost_price = None
                break
        holdings.append(
            Holding(
                symbol=symbol,
                name=str(item.get("name") or item.get("stock_name") or "").strip(),
                quantity=quantity,
                cost_price=cost_price,
                asset_type=infer_asset_type(symbol),
                source_path=request_url,
                ledger_ids=ledger_ids,
            )
        )
    return holdings


def cmd_replay(args: argparse.Namespace) -> int:
    request_path = Path(args.request_json).expanduser().resolve()
    spec = load_request_spec(request_path)
    resp = replay_request(spec)
    out_dir = Path(args.out_dir).expanduser().resolve()
    out_dir.mkdir(parents=True, exist_ok=True)

    raw_path = out_dir / "tzzb_raw_response.txt"
    raw_path.write_text(resp.text, encoding="utf-8")

    result: dict[str, Any] = {
        "status_code": resp.status_code,
        "content_type": resp.headers.get("content-type", ""),
        "url": resp.url,
        "raw_response": str(raw_path),
    }

    parsed_json: Any = None
    try:
        parsed_json = resp.json()
    except Exception:
        parsed_json = None

    if parsed_json is not None:
        json_path = out_dir / "tzzb_raw_response.json"
        json_path.write_text(json.dumps(parsed_json, ensure_ascii=False, indent=2), encoding="utf-8")
        result["raw_json"] = str(json_path)
        holdings = parse_stock_position_payload(parsed_json, resp.url, spec)
        if holdings:
            csv_path = out_dir / args.csv_name
            normalized_json_path = out_dir / args.json_name
            write_csv(csv_path, holdings)
            normalized_json_path.write_text(
                json.dumps(
                    {
                        "source": "tzzb_web_stock_position_api",
                        "request_json": str(request_path),
                        "request_url": resp.url,
                        "status_code": resp.status_code,
                        "summary": summarize_holdings(holdings),
                        "holdings": [
                            {
                                "symbol": h.symbol,
                                "asset_type": h.asset_type,
                                "name": h.name,
                                "quantity": h.quantity,
                                "cost_price": h.cost_price,
                                "source_path": h.source_path,
                                "ledger_ids": h.ledger_ids,
                            }
                            for h in holdings
                        ],
                    },
                    ensure_ascii=False,
                    indent=2,
                ),
                encoding="utf-8",
            )
            result["normalized_csv"] = str(csv_path)
            result["normalized_json"] = str(normalized_json_path)
            result["summary"] = summarize_holdings(holdings)
    print(json.dumps(result, ensure_ascii=False, indent=2))
    return 0 if resp.ok else 1


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="探测同花顺投资账本网页/API 与浏览器登录态痕迹")
    sub = parser.add_subparsers(dest="command", required=True)

    p_scan = sub.add_parser("scan", help="扫描网页 bundle、浏览器 cookie/localStorage/history 痕迹")
    p_scan.add_argument("--page-url", default=DEFAULT_PAGE_URL, help="投资账本页面 URL")
    p_scan.add_argument("--out", default="", help="输出 JSON 文件")
    p_scan.set_defaults(func=cmd_scan)

    p_replay = sub.add_parser("replay", help="用导出的请求 JSON 回放 API，并尽量归一化持仓")
    p_replay.add_argument("--request-json", required=True, help="请求定义 JSON，包含 url/method/headers/cookies/data/json")
    p_replay.add_argument("--out-dir", default=".", help="输出目录")
    p_replay.add_argument("--csv-name", default="ths_selected_holdings.csv", help="归一化 CSV 文件名")
    p_replay.add_argument("--json-name", default="ths_selected_holdings.json", help="归一化 JSON 文件名")
    p_replay.set_defaults(func=cmd_replay)

    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()
    return int(args.func(args))


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
from __future__ import annotations

import argparse
import csv
import json
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Any


DEFAULT_ROOTS = [
    Path.home() / "Library" / "Containers" / "cn.com.10jqka.macstockPro" / "Data",
    Path.home() / "Library" / "Containers" / "cn.com.10jqka.ixcs" / "Data",
    Path.home() / "Library" / "Group Containers" / "group.cn.com.10jqka.ixcs",
]


@dataclass
class Holding:
    symbol: str
    name: str
    quantity: int
    cost_price: float | None
    asset_type: str
    source_path: str
    ledger_ids: list[str]


def normalize_code(value: Any) -> str:
    raw = str(value or "").strip().upper()
    if not raw or raw == "NAN":
        return ""
    if raw.endswith(".XSHG"):
        return raw.replace(".XSHG", ".SH")
    if raw.endswith(".XSHE"):
        return raw.replace(".XSHE", ".SZ")
    if raw.endswith((".SH", ".SZ", ".HK")):
        return raw
    if raw.startswith("SH") and len(raw) >= 8:
        return f"{raw[2:8]}.SH"
    if raw.startswith("SZ") and len(raw) >= 8:
        return f"{raw[2:8]}.SZ"
    if raw.isdigit() and len(raw) == 6:
        market = "SH" if raw.startswith(("5", "6", "9")) else "SZ"
        return f"{raw}.{market}"
    if raw.isdigit() and len(raw) == 5:
        return f"{raw}.HK"
    return raw


def infer_asset_type(symbol: str) -> str:
    code = symbol.split(".")[0]
    if code.startswith(("5", "1", "15")):
        return "fund"
    return "stock"


def normalize_side(value: Any) -> str:
    text = str(value or "").strip().upper()
    if any(k in text for k in ["买", "BUY", "B", "证券买入", "申购"]):
        return "BUY"
    if any(k in text for k in ["卖", "SELL", "S", "证券卖出", "赎回"]):
        return "SELL"
    return text


def discover_roots(extra_roots: list[str] | None = None) -> list[Path]:
    roots = list(DEFAULT_ROOTS)
    containers_root = Path.home() / "Library" / "Containers"
    if containers_root.exists():
        for d in containers_root.iterdir():
            if not d.is_dir():
                continue
            candidate = d / "Data" / "Documents" / "cn.com.10jqka.ixcs"
            if candidate.exists():
                roots.append(d / "Data")
    if extra_roots:
        roots.extend(Path(x).expanduser().resolve() for x in extra_roots)

    uniq: list[Path] = []
    seen: set[Path] = set()
    for p in roots:
        p = p.resolve()
        if p in seen:
            continue
        seen.add(p)
        uniq.append(p)
    return uniq


def list_ledger_files(roots: list[Path]) -> list[Path]:
    files: list[Path] = []
    for root in roots:
        if not root.exists():
