def collapse_pairs(pairs: list[tuple[str, str]]) -> dict[str, Any]:
    result: dict[str, Any] = {}
    for key, value in pairs:
        if key in result:
            existing = result[key]
            if isinstance(existing, list):
                existing.append(value)
            else:
                result[key] = [existing, value]
        else:
            result[key] = value
    return result


def cookie_header_to_dict(cookie_header: str) -> dict[str, str]:
    cookies: dict[str, str] = {}
    for chunk in str(cookie_header or "").split(";"):
        part = chunk.strip()
        if not part or "=" not in part:
            continue
        key, value = part.split("=", 1)
        key = key.strip()
        if key:
            cookies[key] = value.strip()
    return cookies


def normalize_headers(headers: dict[str, Any]) -> tuple[dict[str, str], dict[str, str]]:
    kept: dict[str, str] = {}
    cookies: dict[str, str] = {}
    for raw_key, raw_value in headers.items():
        key = str(raw_key).strip()
        value = str(raw_value).strip()
        if not key or key.lower() in HEADER_DROP_NAMES:
            continue
        if key.lower() == "cookie":
            cookies.update(cookie_header_to_dict(value))
            continue
        kept[key] = value
    return kept, cookies


def parse_body(raw_text: str, content_type: str, params: list[tuple[str, str]] | None = None) -> tuple[str | None, Any]:
    ct = str(content_type or "").lower()
    if params:
        return "data", collapse_pairs(params)

    text = str(raw_text or "").strip()
    if not text:
        return None, None

    if "application/json" in ct or text.startswith("{") or text.startswith("["):
        try:
            return "json", json.loads(text)
        except Exception:
            return "data", text

    if "application/x-www-form-urlencoded" in ct or ("=" in text and "{" not in text):
        pairs = parse_qsl(text, keep_blank_values=True)
        if pairs:
            return "data", collapse_pairs([(str(k), str(v)) for k, v in pairs])

    return "data", text


